import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { useStyles } from '../styles'
import { Input, TextField } from '@material-ui/core';

const PlexusEmail = () => {

    const classes = useStyles()

    const [info, setInfo] = useState({})
    const [ccEmail, setCCEmail] = useState("")

    const [sendGrid, setSendGrid] = useState("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")

    const onFileChange = (e) => {
        e.preventDefault();
        var files = e.target.files, f = files[0];
        if (files[0] !== undefined) {
            var reader = new FileReader();
            reader.onload = function (e) {
                readRaw(e.target.result)
            };
            reader.readAsBinaryString(f)
        }
    }

    const readRaw = (data) => {
        let renderedData = XLSX.read(data, { type: 'binary' });
        const dataParse = XLSX.utils.sheet_to_json(renderedData.Sheets[renderedData.SheetNames[0]], { header: 1 });
        let dict = {}
        let flag = false
        for (let i = 1; i < dataParse.length; i++) {
            if (dataParse[i].length > 1) {
                let cpn = dataParse[i][0]
                let stockCode = dataParse[i][1]
                let mpn = dataParse[i][2]
                let brand = dataParse[i][3]
                let sbjName = dataParse[i][4].trim()
                let email = dataParse[i][5]
                if (cpn.trim() === '' || stockCode.trim() === '' || brand.trim() === '' || sbjName.trim() === '' || email.trim() === '') {
                    alert('Please ensure the following all the following information is available: CPN, Stock Code, Name, Email')
                    flag = true
                    break
                }
                if (email in dict) {
                    dict[email].push({
                        mpn,
                        cpn,
                        stockCode,
                        brand,
                        sbjName
                    })
                } else {
                    dict[email] = [{
                        mpn,
                        cpn,
                        stockCode,
                        brand,
                        sbjName
                    }]
                }
            }
        }
        if (flag) {
            console.log('Input file validation failed')
        } else {
            console.log(`Total Emails: ${Object.keys(dict).length}`)
            setInfo(dict)
        }
    }

    const sendEmail = async () => {
        if (Object.keys(info).length !== 0) {
            const sgMail = require('@sendgrid/mail')
            sgMail.setApiKey(sendGrid)
            for (const [key, v] of Object.entries(info)) {
                let name = info[key][0].sbjName
                if (key !== undefined) {
                    let body = `<table style="line-height:20px;width:100%;text-align:left"><tr><th>CPN</th><th>MFR</th><th>MPN</th></tr>`
                    let cpnList = ''
                    for (let i = 0; i < v.length; i++) {
                        body += `<tr><td><strong>${v[i].cpn}</strong></td><td><strong>${v[i].brand}</strong></td><td><strong>${v[i].stockCode}</strong></td></tr>`
                        cpnList += `${v[i].cpn}`
                        if (i !== v.length - 1) {
                            cpnList += ', '
                        }
                    }
                    body += '</table>'
                    const msg = {
                        to: key,
                        from: 'janice@wiselink.com.sg',
                        cc: ccEmail,
                        subject: `Wiselink - ${cpnList}`,
                        html: `<div style="line-height:7px;margin:0px"><br><p>Hi ${v[0].name},</p><br><p style="line-height:20px;">We cannot find this part(s) in the forecast. Is this part(s) still allocated to Wiselink?</p><br><p>${body}</p><br><p>Kindly help to check and advise?</p><p>Hope to hear from you soon.</p><br><p>Thank you.</p><br><p>Best Regards,</p><p>Janice Lim</p><p>Business Development Manager</p><br><p><strong style="font-size:13px;color:#3b3838">WISELINK TECHNOLOGY PTE LTD</strong></p><p style="font-size:10px;color:#5f5f5f">629 Aljunied Road, #07-04/05 Cititech, Singapore 389838</p><p style="font-size:10px;color:#5f5f5f">Tel: +65 67466066 | Mobile: +65 82811166 | www.wiselink.com.sg</p></div>`,
                    }
                    // const msg = {
                    //     to: 'darryleong95@gmail.com',
                    //     from: 'codeworkssg@gmail.com',
                    //     cc: ccEmail,
                    //     subject: `Wiselink - ${cpnList}`,
                    //     html: `<div style="line-height:7px;margin:0px"><br><p>Hi ${name},</p><br><p style="line-height:20px;">We cannot find this part(s) in the forecast. Is this part(s) still allocated to Wiselink?</p><br><p>${body}</p><br><p>Kindly help to check and advise?</p><p>Hope to hear from you soon.</p><br><p>Thank you.</p><br><p>Best Regards,</p><p>Janice Lim</p><p>Business Development Manager</p><br><p><strong style="font-size:13px;color:#3b3838">WISELINK TECHNOLOGY PTE LTD</strong></p><p style="font-size:10px;color:#5f5f5f">629 Aljunied Road, #07-04/05 Cititech, Singapore 389838</p><p style="font-size:10px;color:#5f5f5f">Tel: +65 67466066 | Mobile: +65 82811166 | www.wiselink.com.sg</p></div>`,
                    // }
                    await sgMail
                        .send(msg)
                        .then(() => {
                            console.log(`Email sent to ${key}`)
                        })
                        .catch((error) => {
                            alert(`Error sending email to ${key}`)
                            console.error(error)
                        })
                }
            }
            alert('Emails sent.')
        }
        else {
            alert('Ensure Valid file is uploaded')
        }
    }

    const handleCC = (e) => {
        setCCEmail(e.target.value)
    }

    return (
        <div className={classes.root}>
            <span style={{ fontSize: '30px', marginBottom: '30px', textAlign: 'center', fontWeight: 'bold' }}>
                Plexus Forecast Comparison
            </span>
            <div className={classes.fileUploadContainer} style={{ flexDirection: 'row', width: '60%' }}>
                <div className={classes.fileUploadWrapper}>
                    <span className={classes.label}>Buyer Booking Details</span>
                    <div className={classes.inputContainer}>
                        <Input onChange={(event) => onFileChange(event, 1)} type="file" className={classes.fileUpload} variant={'filled'}/>
                        <TextField className={classes.fileUpload} label="cc-email" value={ccEmail} onChange={handleCC} rows={1} rowsMax={1} variant={'filled'} />
                    </div>
                </div>
            </div>
            <div style={{ marginTop: '50px' }}>
                <button onClick={() => sendEmail()} className={classes.download}>
                    Send
                </button>
            </div>
        </div>
    );
}


export default PlexusEmail;